fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val dist = Array(m) { Array(n) { Array(k.toInt() + 1) { Long.MAX_VALUE } } }
    dist[0][0][k.toInt()] = 0L
    val queue = PriorityQueue<MutableList<Long>>(Comparator { a, b -> a[0].compareTo(b[0]) })
    queue.add(arrayOf(0L, 0L, 0L, k.toInt()))

    while (queue.isNotEmpty()) {
        val cost = queue.peek()[0]
        val x = queue.peek()[1].toInt()
        val y = queue.peek()[2].toInt()
        val remK = queue.peek()[3].toInt()
        queue.removeAt(0)

        if (x == m - 1 && y == n - 1) {
            return cost
        }

        if (cost > dist[x][y][remK]) {
            continue
        }

        // Move right
        if (y + 1 < n) {
            val newCost = cost + grid[x][y + 1]
            if (newCost < dist[x][y + 1][remK]) {
                dist[x][y + 1][remK] = newCost
                queue.add(arrayOf(newCost, x.toLong(), (y + 1).toLong(), remK))
            }
