            val newCost = cost + grid[x + 1][y]
            if (newCost < dist[x + 1][y][remK]) {
                dist[x + 1][y][remK] = newCost
                queue.add(arrayOf(newCost, (x + 1).toLong(), y.toLong(), remK))
            }
        }

        // Teleport
        if (remK > 0) {
            for (i in 0 until m) {
                for (j in 0 until n) {
                    if (grid[i][j] <= grid[x][y]) {
                        val newCost = cost
                        if (newCost < dist[i][j][remK - 1]) {
                            dist[i][j][remK - 1] = newCost
                            queue.add(arrayOf(newCost, i.toLong(), j.toLong(), remK - 1))
                        }
                    }
                }
            }
        }
    }

    return -1L
}
